def test_result_tables_empty_when_no_tables() -> None:
    """Result tables array is empty when input has no tables."""
    html = "<p>No tables here</p>"
    options = ConversionOptions(include_document_structure=True)

    result = convert(html, options)
    assert result.content  # noqa: S101
    assert len(result.tables) == 0  # noqa: S101


def test_result_tables_multiple() -> None:
    """Multiple tables each appear in the tables array."""
    html = "<table><tr><th>A</th></tr><tr><td>1</td></tr></table><p>Between</p><table><tr><th>B</th></tr><tr><td>2</td></tr></table>"
    options = ConversionOptions(include_document_structure=True)

    result = convert(html, options)
    assert len(result.tables) >= 2  # noqa: S101


